# Fix GitHub Actions CI workflow
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\CIFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath ".github\workflows\security.yml"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  updated security.yml" -ForegroundColor Green
git add .github/workflows/security.yml
git commit -m "fix: CI workflow - remove lockfile requirement"
git push origin main
Write-Host "Done" -ForegroundColor Green